const today = await Memento.system.getCustomDate({relativePosition: 'startOfDay', format: 'iso'});
const startTime = today.replace(/T.*/, 'T09:00:00.000Z');
const futureDay = await Memento.system.getCustomDate({add: {days: 5}, relativePosition: 'startOfDay', format: 'iso'});
const endTime = futureDay.replace(/T.*/, 'T18:00:00.000Z');
const task2 = await Memento.plugins.todo.createTask({
  title: '编写需求分析',
  description: '详细描述项目需求和功能点',
  startDate: startTime,
  dueDate: endTime,
  priority: 'high',
  tags: '["工作","文档","紧急"]'
});
setResult(task2);

const task3 = await Memento.plugins.todo.createTask({
  id: 'task123',
  title: '重要会议',
  description: '与客户讨论项目进展',
  priority: 'high',
  tags: '["工作","会议"]'
});
setResult(`任务已创建，自定义ID: ${task3.id}`);

const updated = await Memento.plugins.todo.updateTask({
  taskId: 'task123',
  updates: {
    title: '新标题',
    priority: 'high',
    tags: ['工作', '紧急', '重要']
  }
});
setResult(updated);

const updated2 = await Memento.plugins.todo.updateTask({
  taskId: 'task123',
  updates: { status: 'inProgress' }
});
setResult(updated2);

const task = await Memento.plugins.todo.findTaskBy({field: 'id', value: 'task123'});
if (task) {
  setResult(`找到任务: ${task.title}`);
} else {
  setResult('未找到该任务');
}

const task = await Memento.plugins.todo.findTaskById({id: 'task123'});
if (task) {
  setResult(`任务: ${task.title}, 状态: ${task.status}`);
} else {
  setResult('任务不存在');
}

const weekStart = await Memento.system.getCustomDate({relativePosition: 'startOfWeek', format: 'iso'});
const weekEnd = await Memento.system.getCustomDate({relativePosition: 'endOfWeek', format: 'iso'});
const tasks = await Memento.plugins.todo.findTasksByStatus({status: 'done', startDate: weekStart, endDate: weekEnd});
setResult(`本周完成 ${tasks.length} 个任务`);
